import { Injectable } from "@nestjs/common";
import crypto from "crypto";

@Injectable()
export class CryptoService {
  private readonly key = Buffer.from(process.env.PLATFORM_SECRET_KEY || "", "base64");

  encrypt(plain: string): string {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv("aes-256-gcm", this.key, iv);
    const encrypted = Buffer.concat([cipher.update(plain, "utf8"), cipher.final()]);
    const tag = cipher.getAuthTag();
    return Buffer.concat([iv, tag, encrypted]).toString("base64");
  }

  decrypt(payload: string): string {
    const raw = Buffer.from(payload, "base64");
    const iv = raw.subarray(0, 12);
    const tag = raw.subarray(12, 28);
    const data = raw.subarray(28);
    const decipher = crypto.createDecipheriv("aes-256-gcm", this.key, iv);
    decipher.setAuthTag(tag);
    return Buffer.concat([decipher.update(data), decipher.final()]).toString("utf8");
  }
}

crypto.service.spec.ts.template:
import { CryptoService } from "./crypto.service";

describe("CryptoService", () => {
  it("round trips plaintext", () => {
    process.env.PLATFORM_SECRET_KEY = Buffer.alloc(32, 1).toString("base64");
    const svc = new CryptoService();
    const enc = svc.encrypt("test");
    const dec = svc.decrypt(enc);
    expect(dec).toBe("test");
  });
});

